    def render_pair(s: str, p: str, o: str) -> str:
        # Basic biographic facts
        if p == "birthDate":
            return f"{s} was born on {o}"
        if p == "birthYear":
            return f"{s} was born in {o}"
        if p == "birthPlace":
            return f"{s} was born in {o}"
        if p == "deathDate":
            return f"{s} died on {o}"
        if p == "deathPlace":
            return f"{s} died in {o}"
        if p == "origin":
            return f"{s} originates from {o}"
        if p == "nationality":
            return f"{s} is {o}"
        if p == "background":
            return f"{s} has a background as {o}"
        # Career / activity
        if p == "occupation":
            return f"{s} works as {o}"
        if p == "activeYearsStartYear":
            return f"{s} started their career in {o}"
        if p == "activeYearsEndYear":
            return f"{s} ended their career in {o}"
        if p == "recordLabel":
            return f"{s} is signed to {o}"
        if p == "associatedBand/associatedMusicalArtist":
            return f"{s} is a member of {o}"
        # Music specifics
        if p == "genre":
            return f"{s} performs {o} music"
        if p == "instrument":
            return f"{s} plays {o}"
        if p == "musicFusionGenre":
            return f"{s} fuses {o}"
        if p == "musicSubgenre":
            return f"{s} is a subgenre of {o}"
        if p == "stylisticOrigin":
            return f"{s} originated from {o}"
        if p == "derivative":
            return f"{s} is a derivative of {o}"
        # Geographic / political
        if p == "country":
            return f"{s} is in {o}"
        if p == "capital":
            return f"The capital of {s} is {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p in {"language", "officialLanguage"}:
            return f"The language of {s} is {o}"
        if p == "currency":
            return f"The currency of {s} is {o}"
        if p == "demonym":
            return f"The demonym for {s} is {o}"
        if p == "areaTotal":
            return f"{s} covers an area of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} is situated at {o} metres above sea level"
        if p == "populationDensity":
            return f"{s} has a population density of {o}"
        if p == "postalCode":
            return f"The postal code of {s} is {o}"
        if p == "meaning":
            return f"The meaning of {s} is {o}"
        if p == "longName":
            return f"The long name of {s} is {o}"
        if p == "foundingDate":
            return f"{s} was founded on {o}"
        if p == "leader":
            return f"The leader of {s} is {o}"
        if p == "leaderTitle":
            return f"The leader title of {s} is {o}"
        if p == "governingBody":
            return f"The governing body of {s} is {o}"
        if p == "parentCompany":
            return f"{s} is owned by {o}"
        if p == "location":
            return f"{s} is located in {o}"
        if p == "anthem":
            return f"The anthem of {s} is {o}"
        if p == "ethnicGroup":
            return f"The main ethnic group of {s} is {o}"
        # Fallback
        return f"{s} {p} {o}"

    # Preserve input order – this often yields a more natural narrative
    phrases: list[str] = [render_pair(t.subject, t.predicate, t.object) for t in triples]

    # Combine phrases into a single fluent sentence
    if len(phrases) == 1:
        sentence = phrases[0]
    else:
        sentence = ", ".join(phrases[:-1]) + ", and " + phrases[-1]

    # Ensure final punctuation
    if not sentence.endswith("."):
        sentence += "."
    return sentence

